        return data[top];
    }

    public boolean isEmpty() { return top == -1; }
    public int size() { return top + 1; }

    public static void main(String[] args) {
        SimpleStack stack = new SimpleStack(5);
        stack.push(10);
        stack.push(20);
        stack.push(30);
